class Solution:
    def maxNumEdgesToRemove(self, n, edges):
        adjA = {i: set() for i in range(1, n + 1)}
        adjB = {i: set() for i in range(1, n + 1)}

        def reachable(adj, u, v):
            if u == v:
                return True
            seen = {u}
            stack = [u]
            while stack:
                cur = stack.pop()
                for nxt in adj[cur]:
                    if nxt == v:
                        return True
                    if nxt not in seen:
                        seen.add(nxt)
                        stack.append(nxt)
            return False

        def add(adj, u, v):
            adj[u].add(v)
            adj[v].add(u)

        used = 0
        for t, u, v in edges:
            if t == 3:
                needed = False
                if not reachable(adjA, u, v):
                    add(adjA, u, v)
                    needed = True
                if not reachable(adjB, u, v):
                    add(adjB, u, v)
                    needed = True
                if needed:
                    used += 1
        for t, u, v in edges:
            if t == 1 and not reachable(adjA, u, v):
                add(adjA, u, v)
                used += 1
        for t, u, v in edges:
            if t == 2 and not reachable(adjB, u, v):
                add(adjB, u, v)
                used += 1

        def all_connected(adj):
            seen = {1}
            stack = [1]
            while stack:
                cur = stack.pop()
                for nxt in adj[cur]:
                    if nxt not in seen:
                        seen.add(nxt)
                        stack.append(nxt)
            return len(seen) == n

        if not all_connected(adjA) or not all_connected(adjB):
            return -1
        return len(edges) - used

