class Solution:
    def maxNumEdgesToRemove(self, n: int, edges):
        parent_a = list(range(n + 1))
        parent_b = list(range(n + 1))

        def find(parent, x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(parent, a, b):
            ra, rb = find(parent, a), find(parent, b)
            if ra == rb:
                return False
            parent[ra] = rb
            return True

        used = 0
        for t, u, v in edges:
            if t == 3:
                ua = union(parent_a, u, v)
                ub = union(parent_b, u, v)
                if ua or ub:
                    used += 1
        for t, u, v in edges:
            if t == 1 and union(parent_a, u, v):
                used += 1
        for t, u, v in edges:
            if t == 2 and union(parent_b, u, v):
                used += 1

        def connected(parent):
            root = find(parent, 1)
            return all(find(parent, i) == root for i in range(1, n + 1))

        if not connected(parent_a) or not connected(parent_b):
            return -1
        return len(edges) - used

