var maxNumEdgesToRemove = function(n, edges) {
    const parentA = Array.from({ length: n + 1 }, (_, i) => i);
    const parentB = Array.from({ length: n + 1 }, (_, i) => i);

    function find(parent, x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }

    function union(parent, a, b) {
        const ra = find(parent, a), rb = find(parent, b);
        if (ra === rb) return false;
        parent[ra] = rb;
        return true;
    }

    let used = 0;
    for (const [t, u, v] of edges) {
        if (t === 3) {
            const ua = union(parentA, u, v);
            const ub = union(parentB, u, v);
            if (ua || ub) used++;
        }
    }
    for (const [t, u, v] of edges) {
        if (t === 1 && union(parentA, u, v)) used++;
    }
    for (const [t, u, v] of edges) {
        if (t === 2 && union(parentB, u, v)) used++;
    }

    function connected(parent) {
        const root = find(parent, 1);
        for (let i = 1; i <= n; i++) {
            if (find(parent, i) !== root) return false;
        }
        return true;
    }

    if (!connected(parentA) || !connected(parentB)) return -1;
    return edges.length - used;
};
